insert into public.concepts
  (id, term, aliases, said, alias_list, status, one_liner, analogy, example, related, deeper, lens_pm, lens_eng, domain, priority)
values
  ('llm', 'LLM', 'Large language model', '“el-el-em”', ARRAY['llm','large language model','large language models']::text[], 'Core', 'The kind of AI behind chatbots — trained on mountains of text to predict what word comes next, one token at a time.', 'Autocomplete that read the whole internet and never gets tired of finishing your sentence.', 'ChatGPT, Claude, and Gemini are all LLMs wearing different coats.', '[{"text":"A specific, huge example of a foundation model.","id":"foundationmodel"},{"text":"Everything it reads and writes is counted in tokens.","id":"tokens"},{"text":"Its confident wrong answers are hallucinations.","id":"hallucination"}]'::jsonb, '“Large” refers to the parameter count — billions to trillions of learned weights. The whole thing is one trick applied at scale: given some text, guess the next token, over and over, until it has written a paragraph. Everything else — reasoning, coding, translation — is that trick generalizing further than anyone expected.', 'The core engine you are building on — general-purpose, capable, and priced per token.', 'A transformer trained with next-token prediction at scale; billions of parameters, autoregressive decoding at inference.', 'Foundations', 80),
  ('tokenization', 'Tokenization', '', '', ARRAY['tokenization','tokenize','tokenizer']::text[], 'Core', 'Chopping text into the bite-size pieces a model actually reads — usually chunks of words, not whole words.', 'Slicing a sentence into LEGO bricks before the model can build with it.', '“tokenization” might split into token-ization — two pieces, not one word.', '[{"text":"The pieces it produces are tokens.","id":"tokens"},{"text":"Why models miscount letters and fumble rare words.","id":"tokens"}]'::jsonb, 'A tokenizer learns a fixed vocabulary of common fragments (often via byte-pair encoding), then greedily splits any text into those fragments. It runs before the model sees anything, which is why a model never really sees letters — only the chunks — and why the same sentence can cost more tokens in one language than another.', 'The step that decides your token count — and therefore your cost and length limits.', 'Deterministic sub-word segmentation (BPE/Unigram) mapping text to integer IDs over a fixed vocabulary.', 'Foundations', 80),
  ('parameters', 'Parameters', 'Weights', '', ARRAY['parameter','parameters']::text[], 'Core', 'The billions of numbers a model tunes during training — its entire learned knowledge, frozen into a giant grid.', 'The settings on an impossibly complex mixing board, dialed in once and then locked.', '“A 70B model” means 70 billion of these numbers doing the work.', '[{"text":"Adjusted a little during fine-tuning.","id":"finetuning"},{"text":"The raw material a neural network is made of.","id":"neuralnetwork"},{"text":"The “large” in large language model.","id":"llm"}]'::jsonb, 'Each parameter is a weight on a connection inside the network. Training nudges all of them, gradually, until the model’s guesses line up with real text. At inference they never change — the model is a fixed function, and the parameters are the function. More parameters usually means more capacity, but also more cost to run.', 'A rough proxy for capability and cost — bigger models know more but are slower and pricier.', 'Learned weights/biases updated by gradient descent in training, static at inference.', 'Foundations', 80),
  ('weights', 'Weights', '', '', ARRAY['weight','weights','model weights']::text[], 'Core', 'The individual learned numbers inside a model — “the weights” is shorthand for the whole trained brain you can download.', 'The recipe card after all the tweaking — hand someone the weights and they can cook the same dish.', '“Open weights” means you can download the numbers and run the model yourself.', '[{"text":"Another word for parameters.","id":"parameters"},{"text":"What fine-tuning nudges.","id":"finetuning"}]'::jsonb, 'Technically weights are one type of parameter (the multipliers on connections), but in practice people say “the weights” to mean the entire trained model file. Whether a lab releases them is the whole open-vs-closed debate: released weights can be run, inspected, and fine-tuned by anyone; withheld ones can only be reached through an API.', 'Whether weights are public decides if you can self-host or are locked to a vendor’s API.', 'The serialized tensor values of a trained network; “open weights” = distributable checkpoint.', 'Foundations', 80),
  ('neuralnetwork', 'Neural network', '', '', ARRAY['neural network','neural net','neural networks']::text[], 'Core', 'The layered math structure underneath modern AI — loosely inspired by brain neurons, but really just numbers flowing through connections.', 'A relay race where each layer passes a refined version of the signal to the next.', 'Every LLM, image generator, and speech model is some flavor of neural network.', '[{"text":"Its connections are the weights.","id":"weights"},{"text":"The transformer is one influential design of one.","id":"llm"}]'::jsonb, 'Input becomes numbers, those numbers pass through layers of weighted sums and simple non-linear functions, and out comes a prediction. Training compares the prediction to the truth and adjusts the weights to shrink the error. “Deep” just means many layers. The brain analogy is mostly marketing — it’s linear algebra, not biology.', 'The umbrella technology; you rarely touch it directly, but it’s what “AI model” refers to.', 'Stacked layers of linear transforms plus non-linearities, trained by backpropagation.', 'Foundations', 80),
  ('foundationmodel', 'Foundation model', '', '', ARRAY['foundation model','foundation models']::text[], 'Core', 'A big, general model trained once on broad data, then adapted to countless specific jobs instead of building one from scratch each time.', 'A liberal-arts graduate you can train up for almost any role, versus hiring a narrow specialist per task.', 'The same base model powers a coding assistant, a support bot, and a summarizer.', '[{"text":"An LLM is a text-based foundation model.","id":"llm"},{"text":"Adapted to a niche via fine-tuning.","id":"finetuning"},{"text":"Or steered at run time with prompt engineering.","id":"promptengineering"}]'::jsonb, 'The term captures a shift: instead of training a bespoke model per task, you train one large general model and adapt it — by prompting, retrieval, or fine-tuning. That reuse is why capabilities spread so fast, and why a handful of expensive base models sit under thousands of products.', 'Build on one general model and specialize it — cheaper and faster than bespoke models per feature.', 'A large pretrained model reused across tasks via prompting, RAG, or fine-tuning.', 'Foundations', 80),
  ('basemodel', 'Base model', '', '', ARRAY['base model','pretrained model']::text[], 'Core', 'The raw, pretrained model before anyone taught it to follow instructions or be polite — powerful but unruly.', 'A brilliant improviser who hasn’t learned to answer the actual question you asked.', 'Hand a base model “Q: capital of France? A:” and it may just keep inventing more Q&As.', '[{"text":"Turned helpful by instruction tuning / fine-tuning.","id":"finetuning"},{"text":"The starting point for a foundation model’s products.","id":"foundationmodel"}]'::jsonb, 'A base model only knows how to continue text, because that’s all it was trained to do. The chat model you actually use is a base model plus alignment steps (instruction tuning, preference training) that teach it to treat your message as a request to fulfill rather than a passage to extend.', 'Usually not what you want directly — the instruction-tuned version is the usable product.', 'Pretrained-only checkpoint (next-token objective), pre-alignment; completes rather than instructs.', 'Foundations', 80),
  ('frontiermodel', 'Frontier model', '', '', ARRAY['frontier model','frontier models']::text[], 'Rising', 'The most capable models out there at any given moment — the current top of the line, wherever the line happens to be.', 'The flagship phone of the year — until next year’s makes it ordinary.', 'When a lab ships its newest, biggest model, that’s a frontier model until the next one lands.', '[{"text":"The cutting-edge end of foundation models.","id":"foundationmodel"},{"text":"Where AI safety debates concentrate.","id":"hitl"}]'::jsonb, 'It’s a moving label, not a fixed tier — today’s frontier is next year’s baseline. The term shows up most in policy and safety conversations, because the newest, most capable systems carry the least-understood risks and draw the most scrutiny before release.', 'Highest capability, highest cost — reach for it when quality matters more than price.', 'The current capability ceiling; typically the largest/newest models under active evaluation.', 'Foundations', 60),
  ('logits', 'Logits', '', '“LOJ-its”', ARRAY['logit','logits']::text[], 'Core', 'The raw scores a model gives every possible next token before picking one — un-normalized “how likely is each word” numbers.', 'The tally of votes for each candidate, before you convert them into percentages.', 'For “The sky is ___”, “blue” gets a high logit, “refrigerator” a very low one.', '[{"text":"Turned into probabilities by softmax.","id":"softmax"},{"text":"Reshaped by the temperature dial.","id":"temperature"}]'::jsonb, 'The final layer outputs one logit per token in the vocabulary. They’re relative scores, not probabilities yet — softmax turns them into a distribution that sums to one. Sampling knobs like temperature and top-p operate on this distribution to decide how adventurous the final pick is.', 'Deep-internals term; matters mainly when you’re tuning how random or safe outputs are.', 'Pre-softmax activations over the vocabulary; scaled by temperature, filtered by top-p/top-k.', 'Foundations', 80),
  ('softmax', 'Softmax', '', '', ARRAY['softmax']::text[], 'Core', 'The math step that turns raw scores into clean percentages that add up to 100% — how the model commits to probabilities.', 'Converting a pile of raw vote counts into a pie chart where the slices sum to a whole.', 'It takes logits like 8, 2, 1 and turns them into something like 95%, 4%, 1%.', '[{"text":"Consumes the raw logits.","id":"logits"},{"text":"Temperature works by stretching or squeezing this step.","id":"temperature"}]'::jsonb, 'Softmax exponentiates each score and divides by the total, so bigger scores dominate and everything lands between 0 and 1. Temperature is literally a divisor applied before this — high temperature flattens the resulting percentages, low temperature sharpens them toward the top pick.', 'Rarely surfaced to users; it’s the plumbing behind “how confident” a model looks.', 'Normalizes logits into a probability distribution; temperature scales the input logits.', 'Foundations', 80),
  ('sampling', 'Sampling', '', '', ARRAY['sampling','sample']::text[], 'Core', 'How the model actually chooses each next word from its list of options — roll the weighted dice, don’t always grab the top one.', 'Drawing from a bag of tiles where common words have more copies, so surprises are possible but rare.', 'Ask the same question twice with sampling on and you can get two different-but-valid answers.', '[{"text":"Chooses among the softmax probabilities.","id":"softmax"},{"text":"Tuned by temperature, top-p, and top-k.","id":"temperature"},{"text":"Its opposite is greedy decoding.","id":"greedydecoding"}]'::jsonb, 'After softmax gives a probability per token, sampling picks one at random weighted by those probabilities. That randomness is why models feel creative and non-repetitive — and why they’re not perfectly reproducible unless you fix the seed or switch to greedy decoding.', 'The reason outputs vary run to run; turn it down for consistency, up for variety.', 'Stochastic token selection from the output distribution, controlled by temperature/top-p/top-k.', 'Foundations', 80),
  ('topp', 'Top-p', 'Nucleus sampling', '“top-pee”', ARRAY['top-p','top p','topp','nucleus sampling']::text[], 'Core', 'A sampling limit that keeps only the smallest set of top choices that together cover, say, 90% of the odds — then picks from those.', 'Only considering the shortlist of front-runners, however long or short that shortlist needs to be.', 'Top-p 0.9 ignores the long tail of unlikely words but keeps genuine contenders in play.', '[{"text":"A gentler cousin of top-k.","id":"topk"},{"text":"Works alongside temperature.","id":"temperature"},{"text":"One knob on the sampling step.","id":"sampling"}]'::jsonb, 'Unlike top-k’s fixed count, top-p adapts: when the model is confident the shortlist is tiny, when it’s unsure the shortlist grows. It trims the improbable tail that can produce nonsense while still allowing variety among reasonable options. Many teams tune top-p instead of, or alongside, temperature.', 'A safer variety dial than temperature alone — cuts nonsense while keeping natural variation.', 'Nucleus sampling: restrict to the smallest token set with cumulative probability ≥ p, then renormalize.', 'Foundations', 80),
  ('topk', 'Top-k', '', '“top-kay”', ARRAY['top-k','top k','topk']::text[], 'Core', 'A sampling limit that keeps only the k most likely next words and throws the rest away before choosing.', 'Only letting the top 40 seeds into the tournament, no matter how the field looks.', 'Top-k 40 means the model picks from its 40 best guesses and ignores everything else.', '[{"text":"The fixed-count sibling of top-p.","id":"topp"},{"text":"A knob on the sampling step.","id":"sampling"}]'::jsonb, 'Top-k is blunt: it always keeps exactly k candidates, even when the model is very sure (so k is too many) or very unsure (so k is too few). That rigidity is why top-p often wins — it adjusts the cutoff to the model’s confidence instead of using a fixed number.', 'An older, blunter variety limit; most teams prefer top-p now.', 'Truncate the distribution to the k highest-probability tokens before sampling.', 'Foundations', 80),
  ('greedydecoding', 'Greedy decoding', '', '', ARRAY['greedy decoding','greedy','greedy search']::text[], 'Core', 'Always taking the single most likely next word — the safe, repeatable, sometimes boring way to generate text.', 'Always ordering the bestseller — reliable, never surprising.', 'Set temperature to 0 and you get greedy decoding: the same answer every time.', '[{"text":"The deterministic opposite of sampling.","id":"sampling"},{"text":"What temperature 0 effectively turns on.","id":"temperature"}]'::jsonb, 'Greedy decoding skips the dice roll and grabs the top token at every step. That makes it reproducible and good for tasks where you want one right answer — extraction, classification, structured output. The cost is blandness and the occasional dead end, since the locally-best word isn’t always the globally-best sentence.', 'Turn it on (temperature 0) when you need consistent, repeatable outputs.', 'Argmax decoding at each step; deterministic, equivalent to temperature→0.', 'Foundations', 80),
  ('positionalencoding', 'Positional encoding', '', '', ARRAY['positional encoding','position embedding','positional embeddings']::text[], 'Fading', 'The trick that tells a model the order of words, since the core machinery would otherwise see your sentence as an unordered pile.', 'Numbering the pages so the story still makes sense after you drop the binder.', 'It’s why “dog bites man” and “man bites dog” land differently instead of looking identical.', '[{"text":"A detail of how the transformer behind an LLM works.","id":"llm"},{"text":"Bounds how the context window scales.","id":"contextwindow"}]'::jsonb, 'Attention treats input as a set, so order has to be injected separately — as a positional signal added to each token. The specific method keeps evolving (sinusoidal, learned, rotary), and it’s a quiet lever behind how far a model’s context window can stretch. Increasingly an under-the-hood detail as newer schemes just work.', 'Deep-internals; matters only when reasoning about very long-context behavior.', 'Injects sequence order into permutation-invariant attention; RoPE and variants affect context extrapolation.', 'Foundations', 30),
  ('vocabulary', 'Vocabulary', '', '', ARRAY['vocabulary','vocab']::text[], 'Core', 'The fixed set of tokens a model knows — every piece it can read or write has to come from this list.', 'The full set of LEGO brick shapes in the box; anything you build uses only those.', 'A common English word is one token in the vocab; a rare name gets spelled out from several.', '[{"text":"Defined by the tokenization step.","id":"tokenization"},{"text":"Each entry is a token.","id":"tokens"}]'::jsonb, 'A tokenizer’s vocabulary is usually tens of thousands of fragments, chosen so frequent text compresses into few tokens. Anything outside it is built up from smaller pieces, which is why unusual words, emoji, or other languages can be surprisingly token-expensive — they don’t have their own dedicated entries.', 'Explains why some inputs cost more tokens than their length suggests.', 'The finite token set from the tokenizer; out-of-vocab text is composed from sub-word units.', 'Foundations', 80)
